// DO NOT Edit this file w/o consulting with the IE build lab.

// Change VER_PRODUCTBUILD and VER_PRODUCTBUILD_QFE as appropriate.

// For IE QFE/SP: We use a project number of "36" for SP builds, and "35" for 
// QFE builds.  When you update the month, update the last two digits of *BOTH*
// instances of the VER_PRODUCTBUILD.

#if (SPVER>=0x20)
#define VER_PRODUCTBUILD		/* Win9x */  3612
#else
#define VER_PRODUCTBUILD		/* Win9x */  3512
#endif

#define VER_PRODUCTBUILD_QFE		/* Win9x */  1702


#define VER_PRODUCTVERSION		4,72,VER_PRODUCTBUILD,VER_PRODUCTBUILD_QFE
#define VER_PRODUCTVERSION_W		(0x0448)
#define VER_PRODUCTVERSION_DW		(0x04480000 | VER_PRODUCTBUILD)


// READ THIS

// Do not change VER_PRODUCTVERSION_STRING.
//
//       Again
//
// Do not change VER_PRODUCTVERSION_STRING.
//
//       One more time
//
// Do not change VER_PRODUCTVERSION_STRING.
//
// ntverp.h will do the right thing wrt the minor version #'s by stringizing
// the VER_PRODUCTBUILD and VER_PRODUCTBUILD_QFE values and concatenating them to
// the end of VER_PRODUCTVERSION_STRING.  VER_PRODUCTVERSION_STRING only needs
// is the major product version #'s. (currently, 4.72)

#define VER_PRODUCTBETA_STR		/* Win9x */  ""
#define VER_PRODUCTVERSION_STRING	"4.72"
